<?php
require __DIR__.'/../includes/bootstrap.php';require_admin();if(!companies_schema_ready())redirect('../upgrade-companies.php');$allowed=['approved','rejected','suspended'];
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$id=(int)($_POST['company_id']??0);$action=$_POST['action']??'';$notes=trim($_POST['review_notes']??'');if(!in_array($action,$allowed,true)){flash('error','Invalid review action.');redirect('companies.php');}$s=db()->prepare('SELECT * FROM companies WHERE id=?');$s->execute([$id]);$c=$s->fetch();if(!$c){flash('error','Company not found.');redirect('companies.php');}db()->beginTransaction();try{db()->prepare('UPDATE companies SET status=?,reviewed_by=?,reviewed_at=NOW(),review_notes=? WHERE id=?')->execute([$action,(int)user()['id'],$notes?:null,$id]);if($action==='approved'){db()->prepare("UPDATE company_members SET company_role=CASE WHEN company_role='pending_owner' THEN 'owner' ELSE company_role END,status='active' WHERE company_id=?")->execute([$id]);}elseif($action==='rejected'){db()->prepare("UPDATE company_members SET status='rejected' WHERE company_id=? AND status='pending'")->execute([$id]);}db()->prepare('INSERT INTO company_approval_history(company_id,action,notes,acted_by) VALUES(?,?,?,?)')->execute([$id,$action,$notes?:null,(int)user()['id']]);db()->commit();flash('success',$action==='approved'?$c['name'].' approved. Official submitters are now Company Owners; fan submitters remain fans.':$c['name'].' marked '.ucfirst($action).'.');}catch(Throwable $e){db()->rollBack();flash('error',$e->getMessage());}redirect('companies.php');}
$status=$_GET['status']??'pending';if(!in_array($status,['pending','approved','rejected','suspended','all'],true))$status='pending';$sql="SELECT c.*,u.display_name AS submitter_name,u.email AS submitter_email,cm.relationship_type,cm.position_title,cm.company_role FROM companies c JOIN users u ON u.id=c.submitted_by LEFT JOIN company_members cm ON cm.company_id=c.id AND cm.user_id=c.submitted_by".($status==='all'?'':' WHERE c.status=?').' ORDER BY c.submitted_at DESC';$s=db()->prepare($sql);$s->execute($status==='all'?[]:[$status]);$companies=$s->fetchAll();app_header('Company Approvals');
?><section class="dashboard-hero"><p class="eyebrow">ADMINISTRATION</p><h1>Company Approvals</h1><p>Review who submitted each company, the position they claim to hold, or whether they are submitting only as a fan.</p></section><p class="admin-actions"><a class="button ghost" href="users.php">Users</a><a class="button ghost" href="identity.php">Identity Options</a></p><div class="filter-links"><?php foreach(['pending','approved','rejected','suspended','all'] as $x):?><a class="<?=$status===$x?'active':''?>" href="?status=<?=$x?>"><?=e(ucfirst($x))?></a><?php endforeach?></div><div class="company-admin-list"><?php foreach($companies as $c):?><article class="app-card company-review-card"><div><span class="status-badge <?=e($c['status'])?>"><?=e(ucfirst($c['status']))?></span><h2><?=e($c['name'])?></h2><p><?=e($c['short_description'])?></p><p class="muted">Submitted by <?=e($c['submitter_name'])?> (<?=e($c['submitter_email'])?>)</p><p><strong>Relationship:</strong> <?=e(ucwords(str_replace('_',' ',$c['relationship_type']??'unknown')))?><?php if($c['position_title']):?> · <strong>Position:</strong> <?=e($c['position_title'])?><?php endif?></p><p><a href="<?=e(base_url('company/dashboard.php?id='.(int)$c['id']))?>">Review company dashboard</a></p></div><form method="post" class="company-review-form"><?=csrf_field()?><input type="hidden" name="company_id" value="<?=(int)$c['id']?>"><label>Review notes<textarea name="review_notes"><?=e($c['review_notes'])?></textarea></label><div class="admin-actions"><button class="button primary small" name="action" value="approved">Approve</button><button class="button ghost small" name="action" value="rejected">Reject</button><button class="button ghost small" name="action" value="suspended">Suspend</button></div></form></article><?php endforeach?><?php if(!$companies):?><article class="app-card"><h2>No <?=e($status)?> companies</h2></article><?php endif?></div><?php app_footer();
